// ── Full 33-seed catalog ──────────────────────────────────────────────────
export const SEED_CATALOG = [
  worldLandmarks, spaceOdyssey, deepOcean, wallStreet, siliconValley,
  ancientEmpires, fantasyKingdom, cyberpunkCity, wildWest, dinosaurEra,
  pirateSeas, arcticExpedition, musicLegends, baseballLeague, foodEmpire,
  movieStudio, cryptoMetaverse, medievalCastle, tropicalParadise, steampunkWorld,
  kpopHallyu, amazonJungle, marsColony, luxuryBrands, artGallery,
  railwayTycoon, volcanoIslands, robotFactory, fairyTale, zombieApocalypse,
  naturalResources, departmentStore, aiWars,
];

export function getSeed(id) {
  return SEED_CATALOG.find(s => s.id === id) || SEED_CATALOG[0];
}

export function getRandomSeed() {
  return SEED_CATALOG[Math.floor(Math.random() * SEED_CATALOG.length)];
}

// ── Build landmark defs from a seed ───────────────────────────────────────
export function buildLandmarkDefs(seed, shuffled = false) {
  let landmarks = [...seed.landmarks];

  if (shuffled) {
    // Shuffle within each phase, maintain phase order
    const byPhase = { Early: [], Mid: [], Late: [] };
    landmarks.forEach(lm => byPhase[lm.phase].push(lm));
    Object.values(byPhase).forEach(arr => {
      for (let i = arr.length - 1; i > 0; i--) {
        const j = Math.floor(Math.random() * (i + 1));
        [arr[i], arr[j]] = [arr[j], arr[i]];
      }
    });
    landmarks = [...byPhase.Early, ...byPhase.Mid, ...byPhase.Late];
  }

  const palette = seed.tonePalette || worldLandmarks.tonePalette;
  const fallbackImg = seed.boardCenter || "assets/ui/world-landmark-main-board.png";

  return landmarks.map((lm, index) => {
    const cost = LANDMARK_COSTS[index];
    return {
      ...lm,
      cost,
      baseRent: Math.round(cost * 0.18),
      upgradeCost: Math.round(cost * 0.58),
      tone: palette[index % palette.length],
      image: seed.images[lm.id] ?? fallbackImg,
      miniProfile: seed.miniatures[lm.id]?.profile ?? "skyscraper",
      miniCrest: seed.miniatures[lm.id]?.crest ?? lm.name.slice(0, 2).toUpperCase(),
    };
  });
}
